function CopyButton({ value }: { value: string }) {
  const { t } = useTranslation('apoyo_vzla');
  const { toast } = useToast();
  const [copied, setCopied] = useState(false);

  const handleCopy = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(value);
      setCopied(true);
      toast({ title: t('payments.copied'), description: value.length > 40 ? value.substring(0, 40) + '…' : value });
      setTimeout(() => setCopied(false), 2200);
    } catch {
      toast({ title: 'Error', description: 'Selecciona y copia manualmente', variant: 'destructive' });
    }
  }, [value, t, toast]);

  return (
    <button
      onClick={handleCopy}
      className="inline-flex items-center gap-1.5 rounded-lg border border-slate-200 bg-white px-3 py-1.5 text-xs font-semibold text-slate-600 transition-colors hover:border-amber-400 hover:bg-amber-50 hover:text-amber-700 shrink-0"
    >
      {copied ? <CheckCircle2 className="h-3.5 w-3.5 text-emerald-500" /> : <Copy className="h-3.5 w-3.5" />}
      {copied ? t('payments.copied') : t('payments.copy')}
    </button>
  );
}

function BankRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between gap-3 border-b border-slate-100 py-2.5 last:border-0">
      <span className="min-w-[130px] text-xs font-medium text-slate-500">{label}</span>
      <span className="flex-1 font-mono text-sm font-semibold text-slate-800 break-all">{value}</span>
      <CopyButton value={value} />
    </div>
  );
}

